            // Clear the dequeued node's link
            unsafe {
                proc_slot_mut(c)
                    .expect("dequeue: c out of range")
                    .next_ready = None;  // line 149
            }
            match prev {
                None => runq.head[prio] = next_after_c,
                Some(pn) => {
                    unsafe {
                        proc_slot_mut(pn)
                            .expect("dequeue: prev out of range")
                            .next_ready = next_after_c;
                    }
                }
            }
            if runq.tail[prio] == Some(c) {
                runq.tail[prio] = prev;
            }
            return;
        }
        prev = Some(c);
        cur = next_after_c;
    }
    // Not found — no-op
}
```

**Linear walk** within a priority band to splice out a process (handles head, middle, tail cases).

