pub fn mini_send(
    proc_table: &mut [Proc; N_PROC_SLOTS],
    priv_table: &mut [Priv; NR_SYS_PROCS],
    caller_nr: ProcNr,
    dst_e: Endpoint,
    user_msg_va: u64,
    flags: SendFlags,
) -> i32 {
    // ... endpoint validation (lines 44-53) ...
    let caller_endpoint = proc_table[caller_idx].endpoint;
    let Some(caller_priv_id) = proc_table[caller_idx].priv_id else {
        return ECALLDENIED;
    };
    let Some(dst_priv_id) = proc_table[dst_idx].priv_id else {
        return ECALLDENIED;
    };

    // ipc_to bitmap: caller must be permitted to send to dst's priv slot.
    if !get_sys_bit(&priv_table[caller_priv_id.as_usize()].ipc_to, dst_priv_id) {
        return ECALLDENIED;  // Lines 64-66: Permission check
    }

    let mut msg = match copy_msg_from_user(user_msg_va) {
        Ok(m) => m,
        Err(e) => return e,
    };
    msg.m_source = caller_endpoint;  // Line 79: Stamp verified caller

    // Immediate-delivery path: destination is RECEIVE-blocked and would accept us.
    {
        let dst = &mut proc_table[dst_idx];
        if will_receive(dst, caller_endpoint) {  // Check if receiver waiting (line 85)
            dst.deliver_msg = msg;
            dst.misc_flags |= MF_DELIVERMSG;
            dst.misc_flags &= !MF_REPLY_PEND;
            unsafe { sched::rts_unset(dst, RTS_RECEIVING) };  // Lines 86-91: Immediate unblock
            return OK;
        }
    }

    if flags == SendFlags::NonBlocking {
        return ENOTREADY;
    }

    // Deadlock check before blocking.
    if deadlock_check(&*proc_table, SEND, caller_nr, dst_e) {
        return ELOCKED;  // Lines 101-103
    }

    // Block: stash msg in caller.send_msg, record sendto_e, mark RTS_SENDING,
    // append to dst.caller_q via q_link.
    {
        let caller = &mut proc_table[caller_idx];
        caller.send_msg = msg;
        caller.sendto_e = dst_e;
        caller.q_link = None;
        unsafe { sched::rts_set(caller, RTS_SENDING) };  // Lines 108-113: Block & queue
    }

    enqueue_on_caller_q(proc_table, dst_idx, caller_nr);
    OK
}
