pub fn mini_pf_send(
    proc_table: &mut [Proc; N_PROC_SLOTS],
    faulting_nr: ProcNr,
    far: u64,
    flags: u32,
) {
    // Both lookups are boot-time invariants
    let fault_idx = proc_index(faulting_nr).expect("mini_pf_send: faulter not in proc table");
    let vm_idx = proc_index(VM_PROC_NR).expect("mini_pf_send: VM server not in proc table");

    let fault_endpoint = proc_table[fault_idx].endpoint;
    let vm_endpoint = proc_table[vm_idx].endpoint;

    // Kernel constructs the message (lines 156-162)
    let mut msg = Message {
        m_source: fault_endpoint,  // Line 157: Sender is the faulter
        m_type: VM_PAGEFAULT,      // Line 158: Message type set by kernel
        payload: [0u8; 96],
    };
    msg.payload[0..8].copy_from_slice(&far.to_ne_bytes());      // Fault address
    msg.payload[8..12].copy_from_slice(&flags.to_ne_bytes());   // Fault flags

    // Immediate delivery: VM is receive-blocked and would accept us.
    {
        let vm = &mut proc_table[vm_idx];
        if will_receive(vm, fault_endpoint) {  // Line 167: Check if receiver waiting
            vm.deliver_msg = msg;
            vm.misc_flags |= MF_DELIVERMSG;
            vm.misc_flags &= !MF_REPLY_PEND;
            // SAFETY: single-threaded EL1 page-fault context; no other borrow
            // into `proc_table` is live.
            unsafe { sched::rts_unset(vm, RTS_RECEIVING) };  // Line 173: Unblock receiver
            return;
        }
    }

    // VM busy: queue the faulter as a blocked sender on VM's caller_q.
    {
        let caller = &mut proc_table[fault_idx];
        caller.send_msg = msg;
        caller.sendto_e = vm_endpoint;
        caller.q_link = None;
        // RTS_PAGEFAULT is already set, so the faulter is already off the run
        // queue; rts_set just OR-s in RTS_SENDING (won't double-dequeue).
        // SAFETY: single-threaded EL1 page-fault context.
        unsafe { sched::rts_set(caller, RTS_SENDING) };  // Line 187: Mark as blocked sender
    }
    enqueue_on_caller_q(proc_table, vm_idx, faulting_nr);  // Line 189: Append to receiver's queue
}
```

**Critical patterns**:
- No `ipc_to` or permission check (kernel-originated, not a user trap)
- No deadlock check (faulter already blocked on fault, VM is the sink)
- `m_source` identifies the faulter (kernel stamps it, user can't spoof)
- Payload carries fault context inline (0..8 = address u64, 8..12 = flags u32)
- Receiver's `caller_q` queues senders when receiver is busy
- `RTS_SENDING` marks a blocked sender; `RTS_PAGEFAULT` keeps the faulter blocked until `VMCTL_CLEAR_PAGEFAULT`

