1	// SPDX-License-Identifier: BSD-3-Clause
2	// Copyright (c) 2025-2026 Kevin Barnard and minix.rs Contributors
3	//! The DS name→endpoint registry (slice 4.2).
4	//!
5	//! DS is the system's directory: every server publishes its own endpoint under
6	//! a key (its NUL-padded name) at init, so others can look each other up by name
7	//! instead of hard-coding boot proc numbers. The store is a flat
8	//! `[Entry; CAP]` — small, fixed, no allocator — wrapped in an
9	//! `UnsafeCell` newtype with `unsafe impl Sync`, exactly like the VM server's
10	//! `region` table and the kernel's `PROC_TABLE`. The single-mutator invariant
11	//! is the same: DS is one EL0 thread with no interrupt handlers of its own, so
12	//! the table is only ever touched from DS's straight-line receive loop.
13	//!
14	//! The pure `*_in` helpers operate on a borrowed array and carry the host unit
15	//! tests; the thin `publish`/`retrieve`/`check` wrappers reach the static and
16	//! are the only `unsafe` here. This keeps the logic measured under coverage
17	//! while the IPC glue in `main.rs` is integration-tested via QEMU.
18	
19	use core::cell::UnsafeCell;
20	
21	use minixrs_kernel_shared::callnr::SYS_GETINFO_NAME_LEN;
22	use minixrs_kernel_shared::error::{EINVAL, ENOMEM, OK};
23	
24	/// Registry key length — a NUL-padded server name. Matches the kernel's
25	/// `GET_WHOAMI` name field so a server can publish under the name it learns at
26	/// startup and clients can look it up by the same bytes.
27	const KEY_LEN: usize = SYS_GETINFO_NAME_LEN;
28	
29	/// Registry capacity. Comfortably covers every boot server (≈11) plus slack;
30	/// no allocator means this is a hard cap, returned as `ENOMEM` when full.
31	const CAP: usize = 16;
32	
33	/// One name→endpoint binding. `in_use == false` marks a free slot.
34	#[derive(Copy, Clone)]
35	struct Entry {
36	    key: [u8; KEY_LEN],
37	    endpoint: i32,
38	    in_use: bool,
39	}
40	
41	impl Entry {
42	    const EMPTY: Self = Self {
43	        key: [0; KEY_LEN],
44	        endpoint: 0,
45	        in_use: false,
46	    };
47	}
48	
49	/// True if `key` is all-NUL (an unset/empty name). Publishing such a key is
50	/// rejected so a zeroed payload can never claim a slot.
51	fn key_is_empty(key: &[u8; KEY_LEN]) -> bool {
52	    key.iter().all(|&b| b == 0)
53	}
54	
55	/// Publish `ep` under `key`. Re-publishing an existing key updates its endpoint
56	/// in place (idempotent, single slot). Returns `OK`, `EINVAL` (empty key), or
57	/// `ENOMEM` (table full).
58	fn publish_in(t: &mut [Entry; CAP], key: &[u8; KEY_LEN], ep: i32) -> i32 {
59	    if key_is_empty(key) {
60	        return EINVAL;
61	    }
62	    // Update an existing binding for this key.
63	    for e in t.iter_mut() {
64	        if e.in_use && &e.key == key {
65	            e.endpoint = ep;
66	            return OK;
67	        }
68	    }
69	    // Otherwise claim the first free slot.
70	    for e in t.iter_mut() {
71	        if !e.in_use {
72	            *e = Entry {
73	                key: *key,
74	                endpoint: ep,
75	                in_use: true,
76	            };
77	            return OK;
78	        }
79	    }
80	    ENOMEM
81	}
82	
83	/// Look up the endpoint registered under `key`, or `None` if unregistered.
84	fn retrieve_in(t: &[Entry; CAP], key: &[u8; KEY_LEN]) -> Option<i32> {
85	    t.iter()
86	        .find(|e| e.in_use && &e.key == key)
87	        .map(|e| e.endpoint)
88	}
89	
90	/// True if `key` is registered.
91	fn check_in(t: &[Entry; CAP], key: &[u8; KEY_LEN]) -> bool {
92	    t.iter().any(|e| e.in_use && &e.key == key)
93	}
94	
95	/// `UnsafeCell`-wrapped static registry. See the module note for the
96	/// single-mutator invariant that makes the `Sync` impl sound.
