1	// SPDX-License-Identifier: BSD-3-Clause
2	// Copyright (c) 2025-2026 Kevin Barnard and minix.rs Contributors
3	//! `SEND` / `SENDNB` — synchronous (and non-blocking) send.
4	//!
5	//! Translation of MINIX 3 `kernel/proc.c:880 mini_send()`. The blocking
6	//! variant either delivers immediately to a waiting receiver or queues
7	//! the caller on the destination's `caller_q` via the `q_link` chain.
8	//! The non-blocking variant returns `ENOTREADY` instead of queueing.
9	
10	use minixrs_kernel_shared::ProcNr;
11	use minixrs_kernel_shared::callnr::VM_PAGEFAULT;
12	use minixrs_kernel_shared::com::{NR_SYS_PROCS, VM_PROC_NR};
13	use minixrs_kernel_shared::endpoint::{Endpoint, endpoint_proc};
14	use minixrs_kernel_shared::error::{EBADSRCDST, ECALLDENIED, ELOCKED, ENOTREADY, OK};
15	use minixrs_kernel_shared::ipc_const::SEND;
16	use minixrs_kernel_shared::message::Message;
17	
18	use crate::ipc::deadlock::deadlock_check;
19	use crate::ipc::message::copy_msg_from_user;
20	use crate::ipc::notify::will_receive;
21	use crate::proc::bitmap::get_sys_bit;
22	use crate::proc::flags::{MF_DELIVERMSG, MF_REPLY_PEND, RTS_RECEIVING, RTS_SENDING};
23	use crate::proc::table::{N_PROC_SLOTS, proc_index};
24	use crate::proc::{Priv, Proc, sched};
25	
26	/// Blocking discipline for [`mini_send`].
27	#[derive(Copy, Clone, Eq, PartialEq, Debug)]
28	pub enum SendFlags {
29	    /// `SEND` — block if the destination cannot accept the message now.
30	    Blocking,
31	    /// `SENDNB` — return [`ENOTREADY`] instead of blocking.
32	    NonBlocking,
33	}
34	
35	/// `SEND` / `SENDNB` primitive.
36	pub fn mini_send(
37	    proc_table: &mut [Proc; N_PROC_SLOTS],
38	    priv_table: &mut [Priv; NR_SYS_PROCS],
39	    caller_nr: ProcNr,
40	    dst_e: Endpoint,
41	    user_msg_va: u64,
42	    flags: SendFlags,
43	) -> i32 {
44	    // TODO(phase 3+): okendpt-style (gen, slot) validation — stale
45	    // endpoints after slot recycle should return EDEADSRCDST. Phase 2
46	    // has no slot recycling, so `endpoint_proc` alone is sufficient.
47	    let dst_nr = endpoint_proc(dst_e);
48	    let Some(dst_idx) = proc_index(dst_nr) else {
49	        return EBADSRCDST;
50	    };
51	    let Some(caller_idx) = proc_index(caller_nr) else {
52	        return EBADSRCDST;
53	    };
54	
55	    let caller_endpoint = proc_table[caller_idx].endpoint;
56	    let Some(caller_priv_id) = proc_table[caller_idx].priv_id else {
57	        return ECALLDENIED;
58	    };
59	    let Some(dst_priv_id) = proc_table[dst_idx].priv_id else {
60	        return ECALLDENIED;
61	    };
62	
63	    // ipc_to bitmap: caller must be permitted to send to dst's priv slot.
64	    if !get_sys_bit(&priv_table[caller_priv_id.as_usize()].ipc_to, dst_priv_id) {
65	        return ECALLDENIED;
66	    }
67	
68	    // Copy the outgoing message out of user memory. The sender cannot
69	    // spoof `m_source` — MINIX 3 stomps it with the kernel's view of the
70	    // caller's endpoint (proc.c:918).
71	    //
72	    // Note: copy precedes deadlock_check deliberately — a userspace bug
73	    // (bad VA) surfaces as EFAULT rather than masquerading as a
74	    // kernel-detected ELOCKED. Keep this ordering.
75	    let mut msg = match copy_msg_from_user(user_msg_va) {
76	        Ok(m) => m,
77	        Err(e) => return e,
78	    };
79	    msg.m_source = caller_endpoint;
80	
81	    // Immediate-delivery path: destination is RECEIVE-blocked and would
82	    // accept us (or ANY).
83	    {
84	        let dst = &mut proc_table[dst_idx];
85	        if will_receive(dst, caller_endpoint) {
86	            dst.deliver_msg = msg;
87	            dst.misc_flags |= MF_DELIVERMSG;
88	            dst.misc_flags &= !MF_REPLY_PEND;
89	            // SAFETY: single-threaded SVC invariant; no other borrow into
90	            // `proc_table` is live.
91	            unsafe { sched::rts_unset(dst, RTS_RECEIVING) };
92	            return OK;
93	        }
94	    }
95	
96	    if flags == SendFlags::NonBlocking {
97	        return ENOTREADY;
98	    }
99	
100	    // Deadlock check before blocking. Reborrow as shared.
101	    if deadlock_check(&*proc_table, SEND, caller_nr, dst_e) {
102	        return ELOCKED;
103	    }
104	
105	    // Block: stash msg in caller.send_msg, record sendto_e, mark
106	    // RTS_SENDING, append to dst.caller_q via q_link.
107	    {
108	        let caller = &mut proc_table[caller_idx];
109	        caller.send_msg = msg;
110	        caller.sendto_e = dst_e;
111	        caller.q_link = None;
112	        // SAFETY: single-threaded SVC invariant.
113	        unsafe { sched::rts_set(caller, RTS_SENDING) };
114	    }
115	
116	    enqueue_on_caller_q(proc_table, dst_idx, caller_nr);
117	    OK
118	}
119	
120	/// Kernel-originated SEND of a `VM_PAGEFAULT` message to the VM server on a
121	/// faulting process's behalf (slice 3.4).
122	///
123	/// Unlike [`mini_send`] there is no user buffer and no caller running an SVC:
124	/// the kernel constructs the message, and the *faulting* process plays the role
125	/// of the (already-blocked) sender. The faulter is expected to already carry
126	/// `RTS_PAGEFAULT` (set by `do_page_fault`); we additionally mark it
127	/// `RTS_SENDING` only when VM can't receive immediately, so that when VM later
128	/// picks it off the `caller_q` ([`super::receive::mini_receive`]'s
129	/// `walk_caller_q` clears `RTS_SENDING`) the lingering `RTS_PAGEFAULT` keeps it
130	/// blocked until `VMCTL_CLEAR_PAGEFAULT`.
131	///
132	/// No `ipc_to`/permission check — the send is kernel-originated, not a user
133	/// trap. No deadlock check either: the faulter is already blocked on a fault
134	/// and VM is its sink, so the SEND↔RECV cycle the detector hunts for can't form.
135	///
136	/// `m_source` identifies the faulter; the payload carries the fault address
137	/// (`0..8`, u64) and fault flags (`8..12`, u32) so VM needs no `GET_PAGEFAULT`
138	/// round-trip to resolve.
139	pub fn mini_pf_send(
140	    proc_table: &mut [Proc; N_PROC_SLOTS],
141	    faulting_nr: ProcNr,
142	    far: u64,
143	    flags: u32,
144	) {
145	    // Both lookups are boot-time invariants: `do_page_fault` has already
146	    // blocked the faulter on RTS_PAGEFAULT before calling us, so a silent
147	    // bailout here would strand it blocked forever with no diagnostic. Halt
148	    // loudly instead (CLAUDE.md: hard assert for invariants that would
149	    // otherwise silently corrupt — here, liveness).
150	    let fault_idx = proc_index(faulting_nr).expect("mini_pf_send: faulter not in proc table");
151	    let vm_idx = proc_index(VM_PROC_NR).expect("mini_pf_send: VM server not in proc table");
152	
153	    let fault_endpoint = proc_table[fault_idx].endpoint;
154	    let vm_endpoint = proc_table[vm_idx].endpoint;
155	
156	    let mut msg = Message {
157	        m_source: fault_endpoint,
158	        m_type: VM_PAGEFAULT,
159	        payload: [0u8; 96],
160	    };
161	    msg.payload[0..8].copy_from_slice(&far.to_ne_bytes());
162	    msg.payload[8..12].copy_from_slice(&flags.to_ne_bytes());
163	
164	    // Immediate delivery: VM is receive-blocked and would accept us.
165	    {
166	        let vm = &mut proc_table[vm_idx];
167	        if will_receive(vm, fault_endpoint) {
168	            vm.deliver_msg = msg;
169	            vm.misc_flags |= MF_DELIVERMSG;
170	            vm.misc_flags &= !MF_REPLY_PEND;
171	            // SAFETY: single-threaded EL1 page-fault context; no other borrow
172	            // into `proc_table` is live.
173	            unsafe { sched::rts_unset(vm, RTS_RECEIVING) };
174	            return;
175	        }
176	    }
177	
178	    // VM busy: queue the faulter as a blocked sender on VM's caller_q.
179	    {
180	        let caller = &mut proc_table[fault_idx];
181	        caller.send_msg = msg;
182	        caller.sendto_e = vm_endpoint;
183	        caller.q_link = None;
184	        // RTS_PAGEFAULT is already set, so the faulter is already off the run
185	        // queue; rts_set just OR-s in RTS_SENDING (won't double-dequeue).
186	        // SAFETY: single-threaded EL1 page-fault context.
187	        unsafe { sched::rts_set(caller, RTS_SENDING) };
188	    }
189	    enqueue_on_caller_q(proc_table, vm_idx, faulting_nr);
190	}
191	
192	/// Append `nr` to the tail of the `caller_q` rooted at `proc_table[dst_idx]`.
193	fn enqueue_on_caller_q(proc_table: &mut [Proc; N_PROC_SLOTS], dst_idx: usize, nr: ProcNr) {
194	    match proc_table[dst_idx].caller_q {
195	        None => {
196	            proc_table[dst_idx].caller_q = Some(nr);
197	        }
198	        Some(head) => {
199	            // Walk the chain to the tail (entry whose q_link is None).
200	            let mut cur = head;
201	            loop {
202	                let cur_idx = proc_index(cur).expect("caller_q entry in range");
203	                match proc_table[cur_idx].q_link {
204	                    Some(next) => cur = next,
205	                    None => {
206	                        proc_table[cur_idx].q_link = Some(nr);
207	                        return;
208	                    }
209	                }
210	            }
211	        }
212	    }
213	}
