204	/// `VMCTL_CLEAR_PAGEFAULT` — clear the target's recorded fault and unblock it.
205	fn clear_pagefault(proc_table: &mut [Proc; N_PROC_SLOTS], target_idx: usize) -> i32 {
206	    let p = &mut proc_table[target_idx];
207	    p.page_fault_state = PageFaultState::EMPTY;
208	    // SAFETY: rts_unset captures `nr` then ends the `p` borrow before enqueue;
209	    // single-threaded EL1 context (same invariant as `do_page_fault`).
