214	/// `VMCTL_GET_PAGEFAULT` — return the target's recorded fault state.
215	///
216	/// Only meaningful while the target is blocked on a page fault; reading it
217	/// otherwise would hand VM stale coordinates, so reject that case.
218	fn get_pagefault(
219	    proc_table: &mut [Proc; N_PROC_SLOTS],
220	    target_idx: usize,
221	    msg: &mut Message,
222	) -> i32 {
223	    let p = &proc_table[target_idx];
224	    if p.rts_flags.load(Ordering::Relaxed) & RTS_PAGEFAULT == 0 {
225	        return EINVAL;
226	    }
227	    let pf = p.page_fault_state;
228	    write_u64(msg, 8, pf.addr);
229	    write_i32(msg, 16, pf.flags as i32);
230	    write_u64(msg, 20, pf.ip);
231	    OK
232	}
233	
234	/// `VMCTL_VMINHIBIT_SET`/`_CLEAR` — gate scheduling of the target while VM
235	/// mutates its address space.
236	fn set_vminhibit(proc_table: &mut [Proc; N_PROC_SLOTS], target_idx: usize, set: bool) -> i32 {
237	    let p = &mut proc_table[target_idx];
238	    // SAFETY: rts_set/rts_unset capture `nr` then end the `p` borrow before
239	    // dequeue/enqueue; single-threaded EL1 context.
240	    unsafe {
241	        if set {
242	            sched::rts_set(p, RTS_VMINHIBIT);
243	        } else {
244	            sched::rts_unset(p, RTS_VMINHIBIT);
245	        }
246	    }
247	    OK
248	}
249	
250	// ----- payload accessors ----------------------------------------------------
251	
252	#[inline]
253	fn read_i32(msg: &Message, off: usize) -> i32 {
254	    i32::from_ne_bytes(
255	        msg.payload[off..off + 4]
256	            .try_into()
257	            .expect("payload in range"),
258	    )
259	}
260	
261	#[inline]
262	fn read_u64(msg: &Message, off: usize) -> u64 {
263	    u64::from_ne_bytes(
264	        msg.payload[off..off + 8]
265	            .try_into()
266	            .expect("payload in range"),
267	    )
268	}
269	
270	#[inline]
271	fn write_i32(msg: &mut Message, off: usize, v: i32) {
272	    msg.payload[off..off + 4].copy_from_slice(&v.to_ne_bytes());
273	}
274	
275	#[inline]
276	fn write_u64(msg: &mut Message, off: usize, v: u64) {
277	    msg.payload[off..off + 8].copy_from_slice(&v.to_ne_bytes());
278	}
