// SPDX-License-Identifier: BSD-3-Clause
// Copyright (c) 2025-2026 Kevin Barnard and minix.rs Contributors
//! `SYS_*` ENOSYS placeholders.
//!
//! Phase 2 ships the dispatch surface and one working handler (`SYS_GETINFO`).
//! Every other Phase-2 `SYS_*` lands here as an `ENOSYS` stub so that
//! `kernel_call_dispatch` can match on every reachable `m_type` and the
//! `k_call_mask` permission check has somewhere to land. Each stub keeps
//! the canonical MINIX 3 `do_*` name so the eventual real implementation
//! can replace it without touching the dispatch table.

use minixrs_kernel_shared::error::ENOSYS;
use minixrs_kernel_shared::message::Message;

use crate::proc::{Priv, Proc};

macro_rules! enosys_stub {
    ($name:ident) => {
        pub(super) fn $name(_caller: &mut Proc, _caller_priv: &Priv, _msg: &mut Message) -> i32 {
            ENOSYS
        }
    };
}

enosys_stub!(do_privctl);
enosys_stub!(do_fork);
enosys_stub!(do_exec);
enosys_stub!(do_exit);
enosys_stub!(do_copy);
enosys_stub!(do_safecopy);
enosys_stub!(do_irqctl);
// `do_vmctl` is a real handler as of slice 3.3 — see `system::do_vmctl`.
enosys_stub!(do_schedule);
enosys_stub!(do_setalarm);
enosys_stub!(do_times);
enosys_stub!(do_diagctl);
enosys_stub!(do_setgrant);

/*
 * minix.rs user-space linker script (aarch64 EL0 servers).
 *
 * Produces a static ET_EXEC ELF that the kernel's minimal loader
 * (`kernel/src/boot_image/elf.rs`) maps segment-by-segment into a fresh
 * per-process AddrSpace. The loader is deliberately tiny, so this script
 * keeps every PT_LOAD page-aligned (vaddr *and* file offset) and emits no
 * dynamic sections / relocations.
 *
 * Load base 0x0010_0000 (1 MiB): comfortably below USER_VA_TOP and clear of
 * the kernel's hand-coded EL0 stub VAs (code 0x40_0000-0x43_0000, stacks
 * 0x80_0000-0x83_0000, stub-D heap 0x0100_0000). The stack is NOT part of
 * the ELF — the kernel allocates a stack frame and sets SP_EL0 before eret.
 * Each server gets its own per-process TTBR0, so this shared load base
 * never collides across servers.
 */

OUTPUT_FORMAT(elf64-littleaarch64)
OUTPUT_ARCH(aarch64)
ENTRY(_start)

PHDRS {
    text   PT_LOAD FLAGS(5); /* R+X */
    rodata PT_LOAD FLAGS(4); /* R   */
    data   PT_LOAD FLAGS(6); /* RW  */
}

SECTIONS {
    . = 0x00100000;

    .text : ALIGN(4K) {
        KEEP(*(.text._start))
        *(.text .text.*)
    } :text

    . = ALIGN(4K);
    .rodata : ALIGN(4K) {
        *(.rodata .rodata.*)
    } :rodata

    . = ALIGN(4K);
    .data : ALIGN(4K) {
        *(.data .data.*)
    } :data

    .bss : ALIGN(4K) {
        *(.bss .bss.*)
        *(COMMON)
    } :data

    /DISCARD/ : {
        *(.eh_frame)
        *(.eh_frame_hdr)
        *(.note .note.*)
        *(.comment)
        *(.dynsym .dynstr .hash .gnu.hash .dynamic)
    }
}

