231	/// Load one boot server's ELF (`elf`) into a fresh address space, prime its
232	/// entry/stack registers, clear the boot `RTS_NO_PRIV` block, and enqueue it.
233	/// Generalizes the slice-3.4 `vm_bootstrap` over the MXBI archive (slice 4.2).
234	///
235	/// Unlike the hand-coded stubs (which use ad-hoc proc/priv slots), a boot server
236	/// occupies its *real* boot slot `nr`: `proc::init` → `init_boot_image` already
237	/// populated its name, priority, endpoint, and privilege slot (`trap_mask =
238	/// SRV_T` → RECEIVE ANY + SEND to any active slot; full `k_call_mask`). So this
239	/// fills in only the address space + EL0 entry state. No `install_*_priv` helper
240	/// is needed.
241	///
242	/// `stack_va` is shared across servers ([`SERVER_STACK_VA`]); each gets its own
243	/// TTBR0, so the same VA maps a distinct frame per server.
244	///
245	/// The `AddrSpace` is `mem::forget`-ed for the same reason as [`build_stub`]:
246	/// the page-table tree is now owned via `Proc::ttbr0_pa`.
247	///
248	/// SAFETY: single-threaded boot; the only writer of `nr`'s proc slot and the
249	/// frame allocator here. Must run after `mm::init_from_limine_memmap` and
250	/// before `sched::run`. `nr` must be a boot server already populated by
251	/// `init_boot_image` (blocked on `RTS_NO_PRIV`).
252	unsafe fn load_boot_server(nr: ProcNr, elf: &[u8], stack_va: u64) {
253	    use crate::arch::aarch64::uart::Pl011;
254	    use core::fmt::Write;
255	
256	    let mut aspace = AddrSpace::new().expect("server AddrSpace::new failed");
257	    let ttbr0_pa = aspace.ttbr0_pa;
258	
259	    let entry =
260	        crate::boot_image::elf::load_into(elf, &mut aspace).expect("server ELF load failed");
261	
262	    // Stack: one zeroed RW page; SP starts at its top.
263	    let stack_frame = alloc_frame().expect("server stack frame alloc failed");
264	    aspace
265	        .map_page(stack_va, stack_frame.addr(), Prot::RW_DATA)
266	        .expect("map_page(server stack) failed");
267	
268	    let asid = unsafe { alloc_asid() };
269	
270	    // SAFETY: single-threaded boot; sole borrow of this server's slot.
271	    unsafe {
272	        let p = proc_slot_mut(nr).expect("server proc slot in range");
273	        p.regs.elr_el1 = entry;
274	        p.regs.sp_el0 = stack_va + PAGE_SIZE as u64;
275	        p.regs.spsr_el1 = STUB_SPSR_EL0;
276	        p.ttbr0_pa = ttbr0_pa;
277	        p.asid = asid;
278	        p.next_ready = None;
279	        // Clear the boot RTS_NO_PRIV: the server now has an address space.
280	        p.rts_flags.store(0, Ordering::Relaxed);
281	
282	        let name = core::str::from_utf8(&p.name)
283	            .unwrap_or("?")
284	            .trim_end_matches('\0');
285	        let _ = writeln!(
286	            Pl011::new(),
287	            "[as] {} nr={} ttbr0_pa={:#x} asid={} entry={:#x}",
288	            name,
289	            p.nr.get(),
290	            p.ttbr0_pa,
291	            p.asid,
292	            entry,
293	        );
294	    }
295	
296	    // The page-table tree is durable via `ttbr0_pa`; don't run `destroy`.
297	    core::mem::forget(aspace);
298	
299	    // SAFETY: single-threaded boot; no other PROC_TABLE / RUNQ borrow is live.
300	    unsafe { sched::enqueue(nr) };
301	}
302	
303	/// Build one stub's address space: allocate L0 + code + stack frames,
304	/// copy the stub blob into the code frame, install RX/RW mappings, and
305	/// write `(ttbr0_pa, asid)` into the proc slot.
306	///
307	/// `aspace` is intentionally `mem::forget`-ed at the end: the page-table
308	/// tree is now owned by the proc (via its `ttbr0_pa`); the kernel will
309	/// only reach into it again via HHDM walks. `AddrSpace::destroy` would
310	/// recursively free every L1/L2/L3 frame plus the L0 root, which is
311	/// exactly what we don't want.
312	///
313	/// SAFETY: single-threaded boot; this is the only writer of `nr`'s proc
314	/// slot. `stub_start..stub_end` must be a valid contiguous rodata range
315	/// in the kernel image; the linker guarantees both.
316	unsafe fn build_stub(
317	    nr: ProcNr,
318	    priv_id: PrivId,
319	    id: u8,
320	    stub_start: *const u8,
321	    stub_end: *const u8,
322	    code_va: u64,
323	    stack_va: u64,
324	    heap_window: HeapWindow,
325	) {
326	    // Per-proc page-table tree. AddrSpace::new allocates and zeroes the
327	    // L0 root via the frame allocator.
328	    let mut aspace = AddrSpace::new().expect("AddrSpace::new failed during userland_bootstrap");
329	    let ttbr0_pa = aspace.ttbr0_pa;
330	
331	    // Code frame: allocate, copy stub bytes in via HHDM, flush I-cache,
332	    // map RO + EL0-executable.
333	    let code_frame = alloc_frame().expect("code frame alloc failed during userland_bootstrap");
334	    // SAFETY: stub_start/stub_end are rodata symbols inside the kernel
335	    // image; the new code frame is exclusively ours (just allocated, not
336	    // yet mapped into any AS) and HHDM-mapped.
337	    unsafe { copy_stub_into_frame(code_frame, stub_start, stub_end) };
338	    aspace
339	        .map_page(code_va, code_frame.addr(), Prot::RO_CODE)
340	        .expect("map_page(code) during userland_bootstrap");
341	
342	    // Stack frame: zeroed by `alloc_frame`, mapped RW + EL0-no-execute.
343	    let stack_frame = alloc_frame().expect("stack frame alloc failed during userland_bootstrap");
344	    aspace
345	        .map_page(stack_va, stack_frame.addr(), Prot::RW_DATA)
346	        .expect("map_page(stack) during userland_bootstrap");
347	
348	    // Hand the AddrSpace's root over to the proc slot.
349	    // SAFETY: single-threaded boot; this is the only `&mut Proc` borrow
350	    // at this nr right now.
351	    let asid = unsafe { alloc_asid() };
352	    unsafe {
353	        let p = proc_slot_mut(nr).expect("stub proc slot in range");
354	        populate_stub_slot(
355	            p,
356	            nr,
357	            priv_id,
358	            id,
359	            code_va,
360	            stack_va + PAGE_SIZE as u64,
361	            ttbr0_pa,
362	            asid,
363	            heap_window,
364	        );
365	    }
366	
367	    // The page-table tree is durable via `ttbr0_pa`. Drop the AddrSpace
368	    // value without running its (no-op-today, but defensively forget'd)
369	    // destructor — leaving `AddrSpace::destroy` reserved for exit/exec
370	    // paths that actually want to tear an AS down.
371	    core::mem::forget(aspace);
372	}
373	
374	/// Copy `[stub_start, stub_end)` into `frame` (resolved via HHDM) and
375	/// flush the I-cache so the upcoming EL0 fetch sees the new bytes.
376	///
377	/// SAFETY: `frame` must be exclusively owned (not yet mapped anywhere)
378	/// and the HHDM mapping for its PA must be live. `stub_start..stub_end`
379	/// must be a valid byte range in the kernel image.
380	unsafe fn copy_stub_into_frame(frame: Frame, stub_start: *const u8, stub_end: *const u8) {
381	    // SAFETY: end >= start by linker layout; offset_from is well-defined
382	    // on a single rodata symbol pair.
383	    let len = unsafe { stub_end.offset_from(stub_start) } as usize;
384	    assert!(len > 0 && len <= PAGE_SIZE);
385	    // SAFETY: caller's invariants hold; we have the sole pointer to this
386	    // frame, and HHDM is the only mapping.
387	    unsafe {
388	        let dst = phys_to_hhdm(frame.addr()) as *mut u8;
389	        core::ptr::copy_nonoverlapping(stub_start, dst, len);
390	        flush_icache_range(dst as u64, len);
391	    }
392	}
393	
394	/// Write all per-stub fields into `p`. Extends slice 2.5's helper with
395	/// `ttbr0_pa` and `asid` — the rest mirrors slice 2.6.
396	fn populate_stub_slot(
397	    p: &mut Proc,
398	    nr: ProcNr,
399	    priv_id: PrivId,
400	    id: u8,
401	    entry_va: u64,
402	    stack_top: u64,
403	    ttbr0_pa: u64,
404	    asid: u8,
405	    heap_window: HeapWindow,
406	) {
407	    // Name: `id` followed by "-stub\0..." padding. Lets the clock tick
408	    // handler print `name[0]` to identify which stub is running.
409	    p.name = [0; 16];
410	    p.name[0] = id;
411	    p.name[1] = b'-';
412	    p.name[2] = b's';
413	    p.name[3] = b't';
414	    p.name[4] = b'u';
415	    p.name[5] = b'b';
416	
417	    p.nr = nr;
418	    p.endpoint = boot_endpoint(nr);
419	    p.priv_id = Some(priv_id);
420	    p.priority = crate::proc::table::SRV_Q;
421	    // 5 ticks per quantum = 50 ms at 100 Hz.
422	    p.quantum_ms = 5;
423	    p.quantum_left = p.quantum_ms as u64;
424	
425	    // EL0 entry state.
426	    p.regs.elr_el1 = entry_va;
427	    p.regs.sp_el0 = stack_top;
428	    p.regs.spsr_el1 = STUB_SPSR_EL0;
429	
430	    // Per-proc address space. Stored on the slot; the scheduler reads
431	    // both on every EL1 → EL0 transition.
432	    p.ttbr0_pa = ttbr0_pa;
433	    p.asid = asid;
434	
435	    // Kernel-resolved heap window (slice 3.2). Empty for A/B/C.
436	    p.page_fault_state = crate::proc::PageFaultState::EMPTY;
437	    p.heap_window = heap_window;
438	
439	    // Run-queue link starts cleared — `sched::enqueue` sets it.
440	    p.next_ready = None;
441	
442	    // Mark runnable.
443	    p.rts_flags.store(0, Ordering::Relaxed);
444	}
445	
446	/// Install priv slots for A, B, C. Unchanged from slice 2.6.
447	///
448	/// SAFETY: single-threaded boot; touches priv-table slots 16, 17, 18
449	/// sequentially.
450	unsafe fn install_stub_privs() {
451	    // SAFETY: sequential mutable borrow.
452	    unsafe {
453	        install_one_stub_priv(STUB_A_PRIV_ID, STUB_A_PROC_NR, STUB_B_PRIV_ID);
454	    }
455	    // SAFETY: A's borrow has been dropped.
456	    unsafe {
457	        install_one_stub_priv(STUB_B_PRIV_ID, STUB_B_PROC_NR, STUB_A_PRIV_ID);
458	    }
459	    // SAFETY: B's borrow has been dropped.
460	    unsafe {
461	        install_stub_c_priv();
462	    }
463	    // SAFETY: C's borrow has been dropped.
464	    unsafe {
465	        install_stub_d_priv();
466	    }
467	}
468	
469	/// Install stub C's priv slot. Differs from the A/B helper: trap_mask =
470	/// USR_T (SENDREC only), ipc_to opened just to SYSTEM, k_call_mask
471	/// opened just to `SYS_GETINFO`.
472	///
473	/// SAFETY: single-threaded boot; mutates only priv-table slot
474	/// `STUB_C_PRIV_ID`.
475	unsafe fn install_stub_c_priv() {
476	    let system_priv_id = {
477	        // SAFETY: read-only snapshot; no live `&mut Proc` here.
478	        let table = unsafe { proc_table_ref() };
479	        let idx = proc_index(SYSTEM).expect("SYSTEM in proc table");
480	        table[idx]
481	            .priv_id
482	            .expect("SYSTEM priv populated by proc::init")
483	    };
484	
485	    // SAFETY: priv index in-range; no overlapping reference held.
486	    let pr: &mut Priv =
487	        unsafe { priv_slot_mut(STUB_C_PRIV_ID).expect("stub C priv slot in range") };
488	    pr.id = STUB_C_PRIV_ID;
489	    pr.proc_nr = Some(STUB_C_PROC_NR);
490	    pr.flags = SYS_PROC | BILLABLE | PREEMPTIBLE;
491	    pr.trap_mask = USR_T;
492	    pr.ipc_to.fill(0);
493	    set_sys_bit(&mut pr.ipc_to, system_priv_id);
494	    pr.k_call_mask.fill(0);
495	    set_call_bit(&mut pr.k_call_mask, (SYS_GETINFO - KERNEL_CALL) as usize);
496	    pr.notify_pending.fill(0);
497	    pr.asyn_pending.fill(0);
498	    pr.sig_mgr = boot_endpoint(RS_PROC_NR);
499	}
500	
501	/// Install stub D's priv slot (slice 3.5/3.6). D drives `brk` and, since slice
502	/// 3.6, `mmap`/`munmap`: it issues `VM_BRK` / `VM_MMAP` / `VM_MUNMAP` SENDRECs to
503	/// the VM server, then touches the regions it created. All three ride the same
504	/// D→VM edge, so D gets `trap_mask = USR_T` (SENDREC only, like stub C) with
505	/// `ipc_to` opened to VM's priv slot and nothing else. `k_call_mask` stays
506	/// empty — D never calls the kernel directly; it talks to VM, and its page
507	/// faults reach VM via the kernel (`mini_pf_send`, which performs no permission
508	/// check).
509	///
510	/// VM's own `ipc_to` was filled by `init_boot_image` only for the active boot
511	/// priv slots `[0, n_active)` (≈ 0..15); stub D's slot is 19, so VM cannot
512	/// reply to D's SENDREC out of the box. This helper also opens that reverse
513	/// direction (VM → D) as a separate, sequential priv-slot borrow.
514	///
515	/// SAFETY: single-threaded boot; mutates priv-table slots `STUB_D_PRIV_ID`
516	/// and VM's slot, one mutable borrow at a time.
517	unsafe fn install_stub_d_priv() {
518	    // Resolve VM's priv id from a read-only snapshot (mirrors stub C resolving
519	    // SYSTEM). No live `&mut Proc`/`&mut Priv` is held here.
520	    let vm_priv_id = {
521	        let table = unsafe { proc_table_ref() };
522	        let idx = proc_index(VM_PROC_NR).expect("VM in proc table");
523	        table[idx].priv_id.expect("VM priv populated by proc::init")
524	    };
525	
526	    // Stub D's own priv slot: SENDREC to VM, nothing else.
527	    // SAFETY: priv index in-range; no overlapping reference held.
528	    {
529	        let pr: &mut Priv =
530	            unsafe { priv_slot_mut(STUB_D_PRIV_ID).expect("stub D priv slot in range") };
531	        pr.id = STUB_D_PRIV_ID;
532	        pr.proc_nr = Some(STUB_D_PROC_NR);
533	        pr.flags = SYS_PROC | BILLABLE | PREEMPTIBLE;
534	        pr.trap_mask = USR_T;
535	        pr.ipc_to.fill(0);
536	        set_sys_bit(&mut pr.ipc_to, vm_priv_id);
537	        pr.k_call_mask.fill(0);
538	        pr.notify_pending.fill(0);
539	        pr.asyn_pending.fill(0);
540	        pr.sig_mgr = boot_endpoint(RS_PROC_NR);
541	    }
542	
543	    // Open VM → D so VM can reply to D's SENDREC. Separate borrow: D's `&mut
544	    // Priv` above has been dropped.
545	    // SAFETY: priv index in-range; no overlapping reference held.
546	    {
547	        let vm_pr: &mut Priv = unsafe { priv_slot_mut(vm_priv_id).expect("VM priv slot in range") };
548	        set_sys_bit(&mut vm_pr.ipc_to, STUB_D_PRIV_ID);
549	    }
550	}
551	
552	/// Set the per-stub priv slot. `peer_priv_id` is the only target the
553	/// stub is permitted to send/notify (encoded as a single bit in
554	/// `ipc_to`).
555	///
556	/// SAFETY: single-threaded boot; mutates only the priv slot at `id`.
557	unsafe fn install_one_stub_priv(id: PrivId, owner: ProcNr, peer_priv_id: PrivId) {
558	    // SAFETY: priv index in-range; no overlapping reference held.
559	    let pr: &mut Priv = unsafe { priv_slot_mut(id).expect("stub priv slot in range") };
560	    pr.id = id;
561	    pr.proc_nr = Some(owner);
562	    pr.flags = SYS_PROC | BILLABLE | PREEMPTIBLE;
563	    pr.trap_mask = SRV_T;
564	    pr.ipc_to.fill(0);
565	    set_sys_bit(&mut pr.ipc_to, peer_priv_id);
566	    pr.k_call_mask.fill(0);
567	    pr.notify_pending.fill(0);
568	    pr.asyn_pending.fill(0);
569	    pr.sig_mgr = boot_endpoint(RS_PROC_NR);
570	}
571	
572	/// Print one line per stub showing its `(ttbr0_pa, asid)`. Run once at
573	/// the end of `userland_bootstrap`; proves each stub has a distinct
574	/// per-proc address space.
575	///
576	/// SAFETY: single-threaded boot; read-only borrows on proc slots 11/12/13/14.
577	unsafe fn print_addrspace_summary() {
578	    use crate::arch::aarch64::uart::Pl011;
579	    use core::fmt::Write;
580	    let mut uart = Pl011::new();
581	    let _ = writeln!(uart);
582	    for &nr in &[
583	        STUB_A_PROC_NR,
584	        STUB_B_PROC_NR,
585	        STUB_C_PROC_NR,
586	        STUB_D_PROC_NR,
587	    ] {
588	        // SAFETY: sequential read-only borrow of the slot; no other
589	        // reference held while we read.
590	        let p = unsafe { proc_slot_mut(nr).expect("stub slot in range") };
591	        let _ = writeln!(
592	            uart,
593	            "[as] stub {} nr={} ttbr0_pa={:#x} asid={}",
594	            p.name[0] as char,
595	            p.nr.get(),
596	            p.ttbr0_pa,
597	            p.asid,
598	        );
599	    }
600	}
601

