2	// Copyright (c) 2025-2026 Kevin Barnard and minix.rs Contributors
3	//! Server runtime — a minimal SEF (System Event Framework) for minix.rs system
4	//! servers (VM today; PM/VFS/RS/DS/SCHED in later Phase 4 slices).
5	//!
6	//! SEF is the shape every server's `main` follows, lifted from MINIX 3's
7	//! `lib/libsys/sef.c` but pared to the essentials:
8	//!
9	//! ```ignore
10	//! let sef = sef_startup(SefConfig { init_fresh: Some(my_init), signal_handler: None })?;
11	//! let mut msg = Message { m_source: 0, m_type: 0, payload: [0u8; 96] };
12	//! loop {
13	//!     if sef.receive(&mut msg) != 0 { continue; }
14	//!     match msg.m_type { /* application requests */ }
15	//! }
16	//! ```
17	//!
18	//! [`sef_startup`] learns the server's own endpoint + name via
19	//! `SYS_GETINFO(GET_WHOAMI)` and runs the registered fresh-init callback.
20	//! [`Sef::receive`] wraps `ipc_receive(ANY, …)` and transparently handles SEF
21	//! control messages (RS heartbeat pings, signals, re-init), returning only
22	//! application traffic to the server.
23	//!
24	//! Unlike MINIX's global `sef_setcb_*` registration, callbacks are passed in a
25	//! [`SefConfig`] and carried in the returned [`Sef`] handle — no static mutable
26	//! state, so the whole crate is `#![forbid(unsafe_code)]` (all `unsafe` lives in
27	//! `minix-ipc`). Live-update / state-transfer SEF features are deferred.
28	
29	// `no_std` for the real (freestanding) build, but a normal host crate under
30	// `cargo test` so the pure [`classify`] logic gets host-runnable unit tests.
31	#![cfg_attr(not(test), no_std)]
32	#![forbid(unsafe_code)]
33	
34	mod classify;
35	mod ds;
36	mod init;
37	mod sef;
38	mod signal;
39	
40	pub use classify::{SefEvent, classify};
41	pub use ds::sef_publish_to_ds;
42	pub use init::SefInitCb;
43	pub use sef::{Sef, SefConfig, sef_startup};
44	pub use signal::SefSignalCb;
45

