242	    #[test]
243	    fn calls_are_contiguous_from_base() {
244	        let calls = [
245	            SYS_GETINFO,
246	            SYS_PRIVCTL,
247	            SYS_FORK,
248	            SYS_EXEC,
249	            SYS_EXIT,
250	            SYS_COPY,
251	            SYS_SAFECOPY,
252	            SYS_IRQCTL,
253	            SYS_VMCTL,
254	            SYS_SCHEDULE,
255	            SYS_SETALARM,
256	            SYS_TIMES,
257	            SYS_DIAGCTL,
258	            SYS_SETGRANT,
259	        ];
260	        for (i, call) in calls.iter().enumerate() {
261	            assert_eq!(*call, KERNEL_CALL + i as i32);
262	        }
263	        assert_eq!(calls.len(), NR_KERN_CALLS_PHASE3);
264	    }
265	
266	    #[test]
267	    fn kernel_call_base_matches_minix3() {
268	        assert_eq!(KERNEL_CALL, 0x600);
269	    }
270	
271	    #[test]
272	    fn get_whoami_matches_minix3() {
273	        // Pinned by MINIX 3 include/minix/sysinfo.h; servers / musl wrappers
274	        // built later in the project depend on this value.
275	        assert_eq!(GET_WHOAMI, 12);
276	    }
277	
278	    #[test]
279	    fn vmctl_subcalls_are_contiguous_from_one() {
280	        // Subcall 0 is reserved as "invalid" (a zeroed payload). The six
281	        // real subcalls are 1..=6 and distinct; `NR_VMCTL_SUBCALLS` locks
282	        // the dispatch coverage in `system::do_vmctl`.
283	        let subcalls = [
284	            VMCTL_PT_MAP,
285	            VMCTL_PT_UNMAP,
286	            VMCTL_CLEAR_PAGEFAULT,
287	            VMCTL_GET_PAGEFAULT,
288	            VMCTL_VMINHIBIT_SET,
289	            VMCTL_VMINHIBIT_CLEAR,
290	        ];
291	        for (i, sc) in subcalls.iter().enumerate() {
292	            assert_eq!(*sc, 1 + i as i32);
293	        }
294	        assert_eq!(subcalls.len(), NR_VMCTL_SUBCALLS);
295	    }
296	
297	    #[test]
298	    fn vm_pagefault_distinct_from_kernel_calls_and_notify() {
299	        // VM requests must not collide with the KERNEL_CALL range, the IPC
300	        // NOTIFY_MESSAGE marker, or any SYS_* number — a server dispatcher
301	        // keys on m_type and a collision would misroute.
302	        assert_eq!(VM_PAGEFAULT, VM_RQ_BASE);
303	        assert!(VM_PAGEFAULT > KERNEL_CALL + NR_KERN_CALLS_PHASE3 as i32);
304	        assert_ne!(VM_PAGEFAULT, crate::ipc_const::NOTIFY_MESSAGE);
305	    }
306	
307	    #[test]
308	    fn vm_brk_follows_pagefault_in_request_range() {
309	        // VM_BRK is the second VM server request, contiguous after VM_PAGEFAULT.
310	        // It must stay distinct from the page-fault request, the KERNEL_CALL
311	        // range, and the NOTIFY marker so VM's m_type dispatcher can't misroute.
312	        assert_eq!(VM_BRK, VM_RQ_BASE + 1);
313	        assert_ne!(VM_BRK, VM_PAGEFAULT);
314	        assert!(VM_BRK > KERNEL_CALL + NR_KERN_CALLS_PHASE3 as i32);
315	        assert_ne!(VM_BRK, crate::ipc_const::NOTIFY_MESSAGE);
316	    }
317	
318	    #[test]
319	    fn vm_mmap_follows_brk_in_request_range() {
320	        // VM_MMAP is the third VM server request, contiguous after VM_BRK.
321	        assert_eq!(VM_MMAP, VM_RQ_BASE + 2);
322	        assert_ne!(VM_MMAP, VM_PAGEFAULT);
323	        assert_ne!(VM_MMAP, VM_BRK);
324	        assert!(VM_MMAP > KERNEL_CALL + NR_KERN_CALLS_PHASE3 as i32);
325	        assert_ne!(VM_MMAP, crate::ipc_const::NOTIFY_MESSAGE);
326	    }
327	
328	    #[test]
329	    fn vm_munmap_follows_mmap_in_request_range() {
330	        // VM_MUNMAP is the fourth VM server request, contiguous after VM_MMAP.
331	        // Each VM request must stay distinct from the others, the KERNEL_CALL
332	        // range, and the NOTIFY marker so VM's m_type dispatcher can't misroute.
