/// (`target.scheduler = NONE`). Absent → the caller claims the target as its
/// own scheduler. Matches MINIX 3 `SCHEDCTL_FLAG_KERNEL` (`include/minix/com.h`).
pub const SCHEDCTL_FLAG_KERNEL: i32 = 1 << 0;

