161	    let priority = rd_i32(msg, 4);
162	
163	    policy::record(
164	        endpoint_proc(target_e).get(),
165	        priority as u8,
166	        policy::QUANTUM,
167	    );
168	    sys_schedule(system, target_e, priority as u8, policy::QUANTUM);
169	
170	    reply(caller_e, msg, OK);
171	}
