50	/// `SYS_SCHEDULE` — set a target's priority + quantum and (re-)admit it.
51	///
52	/// Reads the target endpoint (`SELF` allowed), priority, and quantum from the
53	/// payload; validates them; updates the proc slot; then re-admits the proc:
54	///
55	/// - If the target is **off** the run queue (the `SCHEDULING_NO_QUANTUM` case —
56	///   `reschedule` dequeued it and left `RTS_NO_QUANTUM` set),
57	///   [`sched::rts_unset`] clears the no-quantum block and enqueues it in the
58	///   (possibly new) priority band.
59	/// - If the target is **on** the run queue (runnable already), its band may have
60	///   changed, so move it with `dequeue` + `enqueue`.
61	pub(super) fn do_schedule(
62	    proc_table: &mut [Proc; N_PROC_SLOTS],
63	    caller_nr: ProcNr,
64	    msg: &mut Message,
65	) -> i32 {
66	    let target_e: Endpoint = read_i32(msg, 0);
67	    let priority = read_i32(msg, 4);
68	    let quantum_ms = read_i32(msg, 8);
69	
70	    let target_nr = if target_e == SELF {
71	        caller_nr
72	    } else {
73	        endpoint_proc(target_e)
74	    };
75	    let Some(target_idx) = proc_index(target_nr) else {
76	        return EINVAL;
77	    };
78	
79	    // Priority must name a real band; quantum must be positive. An out-of-range
80	    // priority would otherwise trip `enqueue`'s `prio < NR_SCHED_QUEUES` assert.
81	    if !(0..NR_SCHED_QUEUES as i32).contains(&priority) || quantum_ms <= 0 {
82	        return EINVAL;
83	    }
84	
85	    let (nr, was_runnable) = {
86	        let p = &mut proc_table[target_idx];
87	        let was_runnable = p.rts_flags.load(Ordering::Relaxed) == 0;
88	        p.priority = priority as u8;
89	        p.quantum_ms = quantum_ms as u32;
90	        p.quantum_left = quantum_ms as u64;
91	        (p.nr, was_runnable)
92	    };
93	
94	    // SAFETY: the `p` borrow above has ended (NLL); rts_unset / dequeue / enqueue
95	    // re-borrow `target_idx`'s slot internally. Single-threaded EL1 context, same
96	    // invariant as `do_vmctl`.
97	    unsafe {
98	        if was_runnable {
99	            // Already on the run queue; the new priority may belong to a
100	            // different band, so move it.
101	            sched::dequeue(nr);
102	            sched::enqueue(nr);
103	        } else {
104	            // Off the run queue (preempted, RTS_NO_QUANTUM set): clear the
105	            // no-quantum block and re-admit. rts_unset enqueues in the new band
106	            // if this makes the proc runnable.
107	            sched::rts_unset(&mut proc_table[target_idx], RTS_NO_QUANTUM);
108	        }
109	    }
110	    OK
111	}
