3	//! Priority-banded round-robin scheduler.
4	//!
5	//! Slice 2.4 grows `proc::sched` from the slice-2.3 stub (one fixed
6	//! current-proc tracker) into a real run-queue scheduler. Layout mirrors
7	//! MINIX 3 `kernel/proc.c:1605` (`enqueue`), `:1726` (`dequeue`), and
8	//! `:1795` (`pick_proc`), with two simplifications:
9	//!
10	//! - Queue linkage is a [`ProcNr`] index (`Proc::next_ready`) rather than a
11	//!   raw `struct proc *` — the project-wide convention from `CLAUDE.md`.
12	//! - No per-CPU run queues. Slice 2.4 is single-CPU.
13	//!
14	//! Concurrency model: the kernel runs DAIF-masked, so neither EL1 code nor
15	//! the IRQ handler can be interrupted by *another* IRQ before it finishes.
16	//! The IRQ stub itself is the only async writer; it runs to completion
17	//! before returning to EL0. That gives us the same single-threaded invariant
18	//! as the rest of the boot path, so we use the same `UnsafeCell` + `Sync`
19	//! newtype pattern documented on `ProcStorage` / `PrivStorage`.
20	
21	use core::cell::UnsafeCell;
22	use core::fmt::Write;
23	use core::sync::atomic::{AtomicI32, AtomicU64, Ordering};
24	
25	use minixrs_kernel_shared::ProcNr;
26	use minixrs_kernel_shared::endpoint::{Endpoint, NONE};
27	
28	use crate::arch::ArchRegisterFrame;
29	use crate::proc::Proc;
30	use crate::proc::flags::RTS_NO_QUANTUM;
31	use crate::proc::table::proc_slot_mut;
32	use crate::uart::Uart;
33	
34	/// Leading delegated quantum-exhaust events to trace explicitly, so the boot log
35	/// shows the kernel handing a SCHED-scheduled proc to its scheduler. Steady
36	/// state is dwarfed by stub C's SYS_GETINFO flood, so without a head carve-out
37	/// the modulo-100 `[ksys]` sampler would rarely catch SCHED's re-admit (same
38	/// reasoning as `ipc::TRACE_HEAD` and `do_vmctl::VMCTL_TRACE_HEAD`).
39	const NOQ_TRACE_HEAD: u64 = 6;
40	/// Count of delegated (non-kernel-scheduled) quantum-exhaust events, for the
41	/// head trace above.
42	static NOQ_COUNT: AtomicU64 = AtomicU64::new(0);
43	
44	/// Number of scheduling-priority bands. Matches the constants in
45	/// `proc::table` (`TASK_Q = 0`, `IDLE_Q = 15`).
46	pub const NR_SCHED_QUEUES: usize = 16;
47	
48	/// Currently-running process number. `i32::MIN` is the "no process running"
49	/// sentinel — chosen because it can never collide with a real `ProcNr`
50	/// (kernel tasks are `-5..=-1`, user processes are `0..NR_PROCS`).
51	pub static CURRENT_PROC_NR: AtomicI32 = AtomicI32::new(i32::MIN);
52	
53	const NO_PROC: i32 = i32::MIN;
54	
55	// ---------------------------------------------------------------------------
56	// Run-queue storage.
57	// ---------------------------------------------------------------------------
58	
59	struct RunQueues {
60	    head: [Option<ProcNr>; NR_SCHED_QUEUES],
61	    tail: [Option<ProcNr>; NR_SCHED_QUEUES],
62	}
63	
64	#[repr(transparent)]
65	struct RunQueueStorage(UnsafeCell<RunQueues>);
66	// SAFETY: single-CPU; the kernel runs DAIF-masked, so the only async writer
67	// is the IRQ stub, which runs to completion before returning to EL0. No
68	// concurrent access is possible.
69	unsafe impl Sync for RunQueueStorage {}
70	
71	static RUNQ: RunQueueStorage = RunQueueStorage(UnsafeCell::new(RunQueues {
72	    head: [None; NR_SCHED_QUEUES],
73	    tail: [None; NR_SCHED_QUEUES],
74	}));
75	
76	// ---------------------------------------------------------------------------
77	// Current-proc accessors.
78	// ---------------------------------------------------------------------------
79	
80	/// Borrow the currently-running process's slot.
81	///
82	/// SAFETY: caller must respect the single-threaded-boot invariant on
83	/// `PROC_TABLE`. The returned `&'static mut Proc` must not alias any other
84	/// reference into the table.
85	pub unsafe fn current_proc_mut() -> Option<&'static mut Proc> {
86	    let n = CURRENT_PROC_NR.load(Ordering::Relaxed);
87	    if n == NO_PROC {
88	        return None;
89	    }
90	    // SAFETY: forwarded — caller holds the no-aliasing invariant.
91	    unsafe { proc_slot_mut(ProcNr::new(n)) }
92	}
93	
94	// ---------------------------------------------------------------------------
95	// Run-queue operations.
96	// ---------------------------------------------------------------------------
97	
98	/// Append `nr` to the tail of its priority band's run queue.
99	///
100	/// Mirrors MINIX 3 `kernel/proc.c:1605` `enqueue`. Panics if the process is
101	/// already linked into a queue.
102	///
103	/// SAFETY: caller must hold the single-threaded-boot invariant; no other
104	/// mutable reference into `PROC_TABLE` or `RUNQ` may be live.
105	pub unsafe fn enqueue(nr: ProcNr) {
106	    let prio = unsafe {
107	        let p = proc_slot_mut(nr).expect("enqueue: nr out of range");
108	        assert!(p.next_ready.is_none(), "enqueue: process already queued");
109	        p.priority as usize
110	    };
111	    assert!(prio < NR_SCHED_QUEUES, "enqueue: priority out of range");
112	
113	    // SAFETY: RUNQ is a distinct static from PROC_TABLE; the prior
114	    // proc_slot_mut borrow has been dropped.
115	    let runq = unsafe { &mut *RUNQ.0.get() };
116	    match runq.tail[prio].replace(nr) {
117	        None => {
118	            // Queue was empty — set head too.
119	            runq.head[prio] = Some(nr);
120	        }
121	        Some(prev_tail) => {
122	            // SAFETY: prev_tail was in the queue, so its slot is valid.
123	            let tail_p =
124	                unsafe { proc_slot_mut(prev_tail).expect("enqueue: prev tail out of range") };
125	            tail_p.next_ready = Some(nr);
126	        }
127	    }
128	}
129	
130	/// Splice `nr` out of its priority band's run queue. No-op if not queued.
131	///
132	/// Mirrors MINIX 3 `kernel/proc.c:1726` `dequeue`. Slice 2.4's queues are
133	/// tiny (at most two entries), so the linear walk is fine.
134	///
135	/// SAFETY: caller must hold the single-threaded-boot invariant; no other
136	/// mutable reference into `PROC_TABLE` or `RUNQ` may be live.
137	pub unsafe fn dequeue(nr: ProcNr) {
138	    let prio = unsafe {
139	        proc_slot_mut(nr)
140	            .expect("dequeue: nr out of range")
141	            .priority as usize
142	    };
143	    // SAFETY: RUNQ is a distinct static from PROC_TABLE.
144	    let runq = unsafe { &mut *RUNQ.0.get() };
145	
146	    let mut prev: Option<ProcNr> = None;
147	    let mut cur = runq.head[prio];
148	    while let Some(c) = cur {
149	        // SAFETY: c was on the queue, so its slot is valid; no other live
150	        // reference into c's slot exists here.
151	        let next_after_c = unsafe {
152	            proc_slot_mut(c)
153	                .expect("dequeue: c out of range")
154	                .next_ready
155	        };
156	        if c == nr {
157	            // Clear the dequeued node's link.
158	            // SAFETY: same — single live reference at a time.
159	            unsafe {
160	                proc_slot_mut(c)
161	                    .expect("dequeue: c out of range")
162	                    .next_ready = None;
163	            }
164	            match prev {
165	                None => runq.head[prio] = next_after_c,
166	                Some(pn) => {
167	                    // SAFETY: pn was traversed already and is in the queue.
168	                    unsafe {
169	                        proc_slot_mut(pn)
170	                            .expect("dequeue: prev out of range")
171	                            .next_ready = next_after_c;
172	                    }
173	                }
174	            }
175	            if runq.tail[prio] == Some(c) {
176	                runq.tail[prio] = prev;
177	            }
178	            return;
179	        }
180	        prev = Some(c);
181	        cur = next_after_c;
182	    }
183	    // Not found — leave the queue untouched.
184	}
